mapper.select:
SELECT order_id, user_id, lawyer_id, target_lawyer_id, assignment_type, service_type_id, total_amount, status, created_time, updated_time FROM `order` WHERE status = '待接单' AND lawyer_id IS NULL AND assignment_type = 'PUBLIC'
AND service_type_id = #{serviceTypeId}
ORDER BY created_time DESC

SELECT order_id, user_id, lawyer_id, target_lawyer_id, assignment_type, service_type_id, total_amount, status, created_time, updated_time
FROM `order`
WHERE order_id = #{orderId}

SELECT o.order_id, o.user_id, o.lawyer_id, o.target_lawyer_id, o.assignment_type, o.service_type_id, o.total_amount, o.status, o.created_time, o.updated_time, CAST(d.form_data AS CHAR) AS form_data FROM `order` o LEFT JOIN order_service_detail d ON d.order_id = o.order_id WHERE ( o.lawyer_id = #{lawyerId} OR ( o.assignment_type = 'DIRECT' AND o.target_lawyer_id = #{lawyerId} AND o.lawyer_id IS NULL AND o.status = '待接单' ) ) AND o.status IN ('待接单', '处理中', '待客户确认', '待评价', '已完成', '平台介入')
AND o.status = #{status}
ORDER BY o.updated_time DESC, o.created_time DESC

mapper.update:
UPDATE `order`
SET status = #{newStatus}
WHERE order_id = #{orderId}
  AND status = #{currentStatus}
